// styles.js

import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'relative',
    zIndex: 0,
  },
  heroImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  section: {
    textAlign: 'center',
  },
  imageContainer: {
    position: 'relative',
    marginBottom: theme.spacing(2),
    marginTop: '-25%', // Höjden på den övre bilden
  },
  overlappingImage: {
    marginLeft: '25%',
    width: '150%', // 50% större bredd för den undre bilden
    height: 'auto',
    zIndex: -1, // Flytta undre bilden bakom griden ovanför
  },
  image: {
    width: '100%',
    height: 'auto',
    objectFit: 'cover',
    borderRadius: 0, // Inga rundade hörn
  },
  textContainer: {
    padding: theme.spacing(2),
  },
}));

export default useStyles;
